# branch forward by 4
  beq x12, x14, 1f
  # offset too small to modify counter for checking
1:
  nop

# branch forward by 8
  beq x12, x14, 2f
  addi x1, x1, -2 # shouldn't happen
2:
  addi x1, x1, 4 # should happen

# branch forward by 16
  beq x12, x14, 3f
  addi x1, x1, -8 # shouldn't happen
  j 19f # shouldn't happen
  nop # use up 4 bytes
3:
  addi x1, x1, 16 # should happen

# branch forward by 2048
  .align 11 # align to 2048 bytes
  beq x12, x14, 4f
  addi x1, x1, -32 # shouldn't happen
  j 19f # shouldn't happen
  .align 11 # align to 2048 bytes
4:
  addi x1, x1, 64 # should happen

# branch forward by 4092
  .align 12 # align to 4096 bytes
  nop # use up 4 bytes
  beq x12, x14, 5f
  addi x1, x1, -128 # shouldn't happen
  j 19f # shouldn't happen
  .align 12 # align to 4096 bytes
5:
  addi x1, x1, 256 # should happen

# backward branch by -4
  j 7f # jump around to test backward branch
6:
  j 9f # backward branch succeeded
  # offset too small to modify counter for checking
7:
  beq x12, x14, 6b
  addi x1, x1, -512 # shouldn't happen
  j 19f # shouldn't happen

# backward branch by -8
8:
  addi x1, x1, 1024 # should happen
  j 11f # backward branch succeeded
9:
  beq x12, x14, 8b
  addi x1, x1, -2048 # shouldn't happen
  j 19f # shouldn't happen

# backward branch by 4096
  .align 12 # align to 4096 bytes
10:
  addi x1, x1, 1 # should happen
  j 20f # backward branch succeeded
  .align 12 # align to 4096 bytes
11:
  .insn 0x80e60063 # beq x12, x14, -4096; GCC is turning this into a small branch and a jump
  addi x1, x1, 300 # shouldn't happen
  j 19f # shouldn't happen

# Shouldn't reach here, write failure code
19:
  LI(x1, -1)

